import{_ as a,c as e,o as m,b as t}from"./app.aaa68922.js";const b='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 14","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 14","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","sans":"\u0926\u0943\u0936\u094D\u092F\u0902 \u0936\u0930\u0940\u0930\u092E\u094D","trans":"D\u1E5B\u015Bya\u1E41 \u015Bar\u012Bram","tags":"vim-1","date":"2021-02-13T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/1/14.md"}',r={},o=t('<div class="stanza"><a href="#s1.14" id="s1.14" class="num">1.14</a><div class="sans"><p>\u0908\u0926\u0943\u0936\u0938\u094D\u092F \u092E\u0939\u0947\u091A\u094D\u091B\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u0926\u0943\u0936\u094D\u092F\u0902 \u0936\u0930\u0940\u0930\u092E\u094D\u0965\u0967\u096A\u0965</strong></p></blockquote><p>\u092F\u0926\u094D\u092F\u0926\u094D\u0926\u0943\u0936\u094D\u092F\u0902 \u092C\u093E\u0939\u094D\u092F\u092E\u093E\u092D\u094D\u092F\u0928\u094D\u0924\u0930\u0902 \u0935\u093E \u0924\u0924\u094D\u0924\u0924\u094D\u0938\u0930\u094D\u0935\u092E\u094D \u0905\u0939\u092E\u093F\u0926\u092E\u093F\u0924\u093F\u0938\u0926\u093E\u0936\u093F\u0935\u0935\u0928\u094D\u092E\u0939\u093E\u0938\u092E\u093E\u092A\u0924\u094D\u0924\u094D\u092F\u093E \u0938\u094D\u0935\u093E\u0919\u094D\u0917\u0915\u0932\u094D\u092A\u092E\u0938\u094D\u092F \u0938\u094D\u092B\u0941\u0930\u0924\u093F \u0928 \u092D\u0947\u0926\u0947\u0928\u0964</p><p>\u0936\u0930\u0940\u0930\u0902 \u091A \u0926\u0947\u0939\u0927\u0940\u092A\u094D\u0930\u093E\u0923\u0936\u0942\u0928\u094D\u092F\u0930\u0942\u092A\u0902 \u0928\u0940\u0932\u093E\u0926\u093F\u0935\u0926\u094D\u0926\u0943\u0936\u094D\u092F\u0902 \u0928 \u0924\u0941 \u092A\u0936\u0941\u0935\u0926\u094D\u0926\u094D\u0930\u0937\u094D\u091F\u0943\u0924\u092F\u093E \u092D\u093E\u0924\u093F\u0964 \u090F\u0935\u0902 \u0926\u0947\u0939\u0947 \u092C\u093E\u0939\u094D\u092F\u0947 \u091A \u0938\u0930\u094D\u0935\u0924\u094D\u0930\u093E\u0938\u094D\u092F \u092E\u092F\u0942\u0930\u093E\u0923\u094D\u0921\u0930\u0938\u0935\u0926\u0935\u093F\u092D\u0915\u094D\u0924\u0948\u0935 \u092A\u094D\u0930\u0924\u093F\u092A\u0924\u094D\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u093F\u0964 \u092F\u0925\u094B\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u091C\u0932\u0938\u094D\u092F\u0947\u0935\u094B\u0930\u094D\u092E\u092F\u094B \u0935\u0939\u094D\u0928\u0947\u0930\u094D\u091C\u094D\u0935\u093E\u0932\u093E\u092D\u0919\u094D\u0917\u094D\u092F\u0903 \u092A\u094D\u0930\u092D\u093E \u0930\u0935\u0947\u0903 \u092E\u092E\u0948\u0935 \u092D\u0948\u0930\u0935\u0938\u094D\u092F\u0948\u0924\u093E \u0935\u093F\u0936\u094D\u0935\u092D\u0919\u094D\u0917\u094D\u092F\u094B \u0935\u093F\u0928\u093F\u0930\u094D\u0917\u0924\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u092D\u094B\u0915\u094D\u0924\u0948\u0935 \u092D\u094B\u0917\u094D\u092F\u092D\u093E\u0935\u0947\u0928 \u0938\u0926\u093E \u0938\u0930\u094D\u0935\u0924\u094D\u0930 \u0938\u0902\u0938\u094D\u0925\u093F\u0924\u0903\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u0967\u096A\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5B\u015Basya mahecchasya\u2014</p><blockquote><p><strong>D\u1E5B\u015Bya\u1E41 \u015Bar\u012Bram||14||</strong></p></blockquote><p>Yadyadd\u1E5B\u015Bya\u1E41 b\u0101hyam\u0101bhyantara\u1E41 v\u0101 tattatsarvam ahamidamitisad\u0101\u015Bivavanmah\u0101sam\u0101patty\u0101 sv\u0101\u1E45gakalpamasya sphurati na bhedena|</p><p>\u015Aar\u012Bra\u1E41 ca dehadh\u012Bpr\u0101\u1E47a\u015B\u016Bnyar\u016Bpa\u1E41 n\u012Bl\u0101divadd\u1E5B\u015Bya\u1E41 na tu pa\u015Buvaddra\u1E63\u1E6D\u1E5Btay\u0101 bh\u0101ti| Eva\u1E41 dehe b\u0101hye ca sarvatr\u0101sya may\u016Br\u0101\u1E47\u1E0Darasavadavibhaktaiva pratipattirbhavati| Yathokta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Jalasyevormayo vahnerjv\u0101l\u0101bha\u1E45gya\u1E25 prabh\u0101 rave\u1E25 Mamaiva bhairavasyait\u0101 vi\u015Bvabha\u1E45gyo vinirgat\u0101\u1E25||</p></blockquote><p>iti| Etacca</p><blockquote><p>Bhoktaiva bhogyabh\u0101vena sad\u0101 sarvatra sa\u1E41sthita\u1E25|</p></blockquote><p>ityanena sa\u1E45g\u1E5Bh\u012Btam||14||</p></div><hr><p>\u0414\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0442\u0438\u043F\u0430 <em>(\u012Bd\u1E5B\u015Basya)</em> [Yog\u012B], \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0435\u0433\u043E \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0438\u043B\u044B \u0412\u043E\u043B\u0438 <em>(mah\u0101-icchasya)</em>\u2014</p><blockquote><p><strong>\u0412\u0441\u0435 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u044B [\u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435] <em>(d\u1E5B\u015Byam)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0442\u0435\u043B\u043E\u043C <em>(\u015Bar\u012Bram)</em> [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B]||14||</strong></p></blockquote><p>\u0427\u0442\u043E \u0431\u044B \u043D\u0438 <em>(yad yad)</em> \u0431\u044B\u043B\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u043E <em>(d\u1E5B\u015Byam)</em>, [\u0431\u0443\u0434\u044C \u0442\u043E] \u0432\u043D\u0435\u0448\u043D\u0435 <em>(b\u0101hyam)</em> \u0438\u043B\u0438 <em>(v\u0101)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 <em>(\u0101bhyantaram)</em> [\u0419\u043E\u0433\u0438\u043D\u043E\u043C,] \u0434\u043B\u044F \u043D\u0435\u0433\u043E <em>(asya)</em> \u0432\u0441\u0435 <em>(sarvam)</em>, \u0447\u0442\u043E <em>(tad tad)</em> \u0441\u0438\u044F\u0435\u0442 <em>(sphurati)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(kalpam)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 <em>(sva)</em> \u0442\u0435\u043B\u0443 <em>(a\u1E45ga)</em>, \u0430 \u043D\u0435 \u043A\u0430\u043A \u0447\u0442\u043E-\u0442\u043E, \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0435 [\u043E\u0442 \u043D\u0435\u0433\u043E] <em>(na bhedena)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F [\u0435\u0433\u043E] \u0432\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044E <em>(mah\u0101-sam\u0101patty\u0101)</em>, [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u044F] &quot;\u042F <em>(aham)</em> [\u0435\u0441\u0442\u044C] \u042D\u0442\u043E <em>(idam iti)</em>&quot; --\u0442.\u0435. \u042F \u0435\u0441\u0442\u044C \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F-- \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> Sad\u0101\u015Biva <em>(sad\u0101\u015Biva)</em><sup>1</sup> --K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u044D\u0442\u043E\u0442 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0432 \u0435\u0433\u043E \u043E\u0431\u044B\u0447\u043D\u043E\u043C \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0438, \u0442.\u0435. &quot;D\u1E5B\u015Bya\u1E41 \u015Bar\u012Bram&quot;; \u043D\u043E \u0435\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u0431\u0437\u0430\u0446\u0430 \u0431\u0443\u0434\u0443\u0442 \u0431\u0430\u0437\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0438 &quot;\u015Aar\u012Bra\u1E41 d\u1E5B\u015Bya\u1E41&quot;--|</p><p>\u0422\u0430\u043A\u0436\u0435 <em>(ca)</em>, [\u0434\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0442\u0438\u043F\u0430 Yog\u012B], \u015Bar\u012Bra, \u0438\u043B\u0438 \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bram)</em>, [\u0432 \u043B\u044E\u0431\u043E\u0439 ] \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bpam)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043B\u0438 \u0442\u0435\u043B\u0430 <em>(deha)</em>, \u043C\u044B\u0441\u043B\u0435\u0439 <em>(dh\u012B)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0438\u043B\u0438] \u043F\u0443\u0441\u0442\u043E\u0442\u044B <em>(\u015B\u016Bnya)</em> [\u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0438, \u0441\u043D\u0435 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0442.\u0434.], \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bh\u0101ti)</em> \u043A\u0430\u043A \u0444\u0435\u043D\u043E\u043C\u0435\u043D --\u0442.\u0435. \u0447\u0442\u043E-\u0442\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0435-- <em>(d\u1E5B\u015Byam)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> \u0441\u0438\u043D\u0435\u043C\u0443 [\u0446\u0432\u0435\u0442\u0443] <em>(n\u012Bla)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u0430 \u043D\u0435 <em>(na tu)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u043C\u0443 <em>(dra\u1E63\u1E6D\u1E5Btay\u0101)</em>, \u043A\u0430\u043A \u0432 [\u0441\u043B\u0443\u0447\u0430\u0435] <em>(vat)</em> \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 (\u043F\u0430\u0448\u0443) <em>(pa\u015Bu)</em><sup>2</sup>|</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0432 \u0442\u0435\u043B\u0435 <em>(dehe)</em>, \u0432\u043E\u0432\u043D\u0435 <em>(b\u0101hye)</em> \u0438 <em>(ca)</em> \u0432\u0435\u0437\u0434\u0435 <em>(sarvatra)</em>, \u0435\u0433\u043E <em>(asya)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(pratipatti\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bhavati)</em>, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(eva)</em>, \u043D\u0435\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C, \u0438\u043B\u0438 \u043D\u0435\u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C <em>(avibhakt\u0101)</em>, \u043A\u0430\u043A <em>(vat)</em> \u043F\u043B\u0430\u0437\u043C\u0430 <em>(rasa)</em> \u044F\u0439\u0446\u0430 \u043F\u0430\u0432\u043B\u0438\u043D\u0430 <em>(may\u016Bra-a\u1E47\u1E0Da)</em> --\u0442.\u0435. \u0435\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0434\u043D\u043E\u0440\u043E\u0434\u043D\u043E, \u043A\u0430\u043A \u0442\u0430 \u043F\u043B\u0430\u0437\u043C\u0430--|</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012B)</em> Vij\xF1\u0101nabhairava <em>(vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;[\u0422\u0430\u043A\u0436\u0435 \u043A\u0430\u043A] \u0432\u043E\u043B\u043D\u044B <em>(\u016Brmaya\u1E25)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0430\u0441\u043F\u0435\u043A\u0442\u043E\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F] \u0432\u043E\u0434\u044B <em>(jalasya)</em>, \u044F\u0437\u044B\u043A\u0438 \u043F\u043B\u0430\u043C\u0435\u043D\u0438 <em>(jv\u0101l\u0101-bha\u1E45gya\u1E25)</em> [\u2014 \u0430\u0441\u043F\u0435\u043A\u0442\u043E\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F] \u043E\u0433\u043D\u044F <em>(vahne\u1E25)</em> [\u0438] \u0441\u0432\u0435\u0442 <em>(prabh\u0101)</em> [\u2014 \u0430\u0441\u043F\u0435\u043A\u0442\u043E\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F] \u0441\u043E\u043B\u043D\u0446\u0430 <em>(rave\u1E25)</em>, [\u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435] \u044D\u0442\u0438 <em>(et\u0101\u1E25)</em> \u0430\u0441\u043F\u0435\u043A\u0442\u044B --\u043A\u0430\u043A \u0432\u043E\u043B\u043D\u044B-- <em>(bha\u1E45gya\u1E25)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> \u0432\u044B\u0448\u043B\u0438 <em>(vinirgat\u0101\u1E25)</em> \u0438\u0437 \u041C\u0435\u043D\u044F <em>(mama eva)</em>, \u0442.\u0435. \u0438\u0437 Bhairava <em>(bhairavasya... iti)</em>&quot;||</p></blockquote><p>\u042D\u0442\u043E <em>(etad ca)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u044D\u0442\u043E\u0439 [\u0447\u0430\u0441\u0442\u044C\u044E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(anena)</em> [\u0438\u0437 Spandak\u0101rik\u0101-s]:</p><blockquote><p>&quot;... \u0421\u0430\u043C \u042D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0430\u0442\u043E\u0440 <em>(bhokt\u0101 eva)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> [\u0438] \u0432\u0435\u0437\u0434\u0435 <em>(sarvatra)</em>, \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(sa\u1E41sthita\u1E25)</em> \u0432 \u0432\u0438\u0434\u0435 <em>(bh\u0101vena)</em> \u0438\u0441\u043F\u044B\u0442\u0443\u0435\u043C\u043E\u0433\u043E <em>(bhogya... iti)</em>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s II, 4]</p></blockquote><p>||14||</p><hr><ol><li><p>Sad\u0101\u015Biva \u2014 \u044D\u0442\u043E \u0442\u0440\u0435\u0442\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u041A\u043E\u0433\u0434\u0430 \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u044F\u044F \u0421\u0438\u043B\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u044D\u043A\u0441\u0442\u0440\u0430\u0433\u0438\u0440\u0443\u0435\u0442 \u0438\u0437 \u0421\u0435\u0431\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E (Idam, \u0438\u043B\u0438 \u042D\u0442\u043E), Idam \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043D\u0435\u0447\u0435\u0442\u043A\u0438\u0439 (\u0442\u0443\u043C\u0430\u043D\u043D\u044B\u0439). \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u0432\u0435 \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u044F\u0432\u043B\u044F\u044E\u0442 \u0441\u043E\u0431\u043E\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0438 \u0415\u0433\u043E \u0421\u0438\u043B\u0443 (\u015Aiva \u0438 \u015Aakti), Sad\u0101\u015Biva \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u0414\u043E Sad\u0101\u015Biva, \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 &quot;\u042F \u0435\u0441\u0442\u044C&quot;, \u043D\u043E \u043A\u0430\u043A \u0442\u043E\u043B\u044C\u043A\u043E Sad\u0101\u015Biva \u043F\u0440\u043E\u044F\u0432\u0438\u043B\u0441\u044F, \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043E\u0449\u0443\u0449\u0430\u0435\u0442 &quot;\u042F \u0435\u0441\u0442\u044C \u042D\u0442\u043E&quot;, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E Idam, \u0438\u043B\u0438 \u042D\u0442\u043E (\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F) \u043D\u0430\u0447\u0430\u043B\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F \u0415\u0433\u043E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0438\u043B\u043E\u0439. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0433\u043E \u0438\u0434\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438 \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F, Yog\u012B \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u0442 \u0442\u043E\u0442 \u0436\u0435 \u043E\u043F\u044B\u0442, \u0447\u0442\u043E \u0438 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439.</p></li><li><p>K\u1E63emar\u0101ja \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0437\u0434\u0435\u0441\u044C, \u0447\u0442\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0441\u043B\u043E\u0432\u0430 \u015Bar\u012Bra \u2014 &quot;\u0442\u0435\u043B\u043E&quot;, \u043D\u043E \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E &quot;\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E&quot;. \u041E\u043D \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u044D\u0442\u043E &quot;\u0442\u0435\u043B\u043E&quot; \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C \u0444\u043E\u0440\u043C\u0443 \u043C\u044B\u0441\u043B\u0438 (\u0432\u043E \u0441\u043D\u0435), \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 (\u0432 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u043C \u0441\u043D\u0435) \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u043F\u0443\u0441\u0442\u043E\u0442\u044B (\u0432 M\u0101y\u0101) \u0442\u0430\u043A\u0436\u0435. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u043C\u0443\u0434\u0440\u0435\u0446 \u044F\u0441\u043D\u043E \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0442\u043E\u0442 \u0444\u0430\u043A\u0442, \u0447\u0442\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442 \u015Bar\u012Bra, \u0438\u043B\u0438 \u0442\u0435\u043B\u043E \u043A\u0430\u043A \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0442\u0430\u043A \u043D\u0435 \u0441\u0447\u0438\u0442\u0430\u0435\u0442. \u0412\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u015Bar\u012Bra \u043A\u0430\u043A \u0435\u0449\u0435 \u043E\u0434\u0438\u043D \u043E\u0431\u044A\u0435\u043A\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C. \u0410 \u043F\u043E\u0447\u0435\u043C\u0443 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442 \u015Bar\u012Bra \u043A\u0430\u043A \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u0438 \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441 \u015Bar\u012Bra, \u0442.\u0435. \u0441 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C, \u043C\u044B\u0441\u043B\u044F\u043C\u0438, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 \u0438\u043B\u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u043E\u0439. \u041E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u015Bar\u012Bra \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u043E\u0439 \u043E\u0448\u0438\u0431\u043A\u043E\u0439, \u0442\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 \u0442\u044F\u0436\u0435\u043B\u043E\u0435 \u0431\u0440\u0435\u043C\u044F \u0438\u0445 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u0445 \u0434\u0435\u043B\u0430\u0442\u044C \u044D\u0442\u0443 \u043E\u0448\u0438\u0431\u043A\u0443. \u0418 \u043A\u0430\u043A\u043E\u0439 \u0432\u044B\u0445\u043E\u0434 \u0434\u043B\u044F \u043D\u0438\u0445?: &quot;\u041E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439, \u0442.\u0435. \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C&quot;. \u041E\u0434\u043D\u0430\u043A\u043E, \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u0438\u044E \u044D\u0442\u043E\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439, \u043F\u0430\u0440\u0430\u0434\u043E\u043A\u0441\u0430\u043B\u044C\u043D\u043E, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u043C\u0438 \u0441\u0430\u043C\u0438\u043C\u0438.</p></li></ol></div>',1),i=[o];function p(s,v,h,d,u,n){return m(),e("div",null,i)}var y=a(r,[["render",p]]);export{b as __pageData,y as default};
